WHERE c.is_deleted = 0

    AND c.driver_id = #{driverId}


    AND d.company_id = #{companyId}


    AND d.phone LIKE CONCAT('%', #{driverPhone}, '%')


    AND c.car_no LIKE CONCAT('%', #{carNo}, '%')


    AND c.brand_name LIKE CONCAT('%', #{brandName}, '%')


    AND c.ride_type_id = #{rideTypeId}


    AND c.city_code = #{cityCode}


    AND c.city_code LIKE CONCAT(SUBSTRING(#{provinceCode}, 1, 2), '%')

mapper.select:
SELECT



ORDER BY c.id DESC
LIMIT #{offset}, #{limit}
